<?php
namespace Tests\Feature;
use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Equipment\CharacterEquipmentSlot;use App\Domain\Equipment\Exceptions\EquipmentLoadoutConflictException;use App\Domain\Inventory\Instances\ItemInstanceEventType;use App\Models\Character;use App\Models\CharacterClass;use App\Models\CharacterEquipment;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Str;use InvalidArgumentException;use Tests\TestCase;
class EquipmentHandLoadoutTest extends TestCase{use RefreshDatabase;private $origin=910000;private function character($dual=false){$class=CharacterClass::factory()->create(['can_dual_wield'=>$dual]);return Character::factory()->selected()->for(User::factory())->create(['character_class_id'=>$class->id,'base_attack'=>10]);}private function item($requirement,$family,$bonus=0){return Item::create(['code'=>'hand_'.Str::random(12),'name'=>$family,'item_type'=>'equipment','equipment_type'=>'weapon','hand_requirement'=>$requirement,'equipment_family'=>$family,'required_level'=>1,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active','attack_bonus'=>$bonus]);}private function handInstance(Character $character,Item $item){return ItemInstance::create(['uuid'=>(string)Str::uuid(),'character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>0,'status'=>'available','origin_type'=>'legacy_inventory','origin_id'=>$this->origin++,'origin_unit_index'=>1,'acquired_at'=>now()]);}
public function test_nine_real_slots_legacy_and_pet_boundaries(){ $this->assertCount(9,CharacterEquipmentSlot::all());$this->assertContains('off_hand',CharacterEquipmentSlot::all());$this->assertNotContains('pet',CharacterEquipmentSlot::all());$legacy=Item::create(['code'=>'legacy_hand','name'=>'Legacy','item_type'=>'equipment','equipment_type'=>'weapon','hand_requirement'=>null,'equipment_family'=>null,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$character=$this->character();$instance=$this->handInstance($character,$legacy);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$this->assertDatabaseHas('character_equipment',['slot'=>'main_hand']);app(CharacterEquipmentService::class)->unequip($character,'main_hand');$this->expectException(InvalidArgumentException::class);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'off_hand');}
public function test_individual_hand_configuration_rules(){ $character=$this->character();$service=app(CharacterEquipmentService::class);$two=$this->handInstance($character,$this->item('two_hand','sword'));try{$service->equip($character,$two->uuid,'off_hand');$this->fail();}catch(InvalidArgumentException $e){}$support=$this->handInstance($character,$this->item('off_hand_only','shield'));try{$service->equip($character,$support->uuid,'main_hand');$this->fail();}catch(InvalidArgumentException $e){}$helmet=Item::create(['code'=>'bad_hand_helmet','name'=>'Bad','item_type'=>'equipment','equipment_type'=>'helmet','hand_requirement'=>'one_hand','equipment_family'=>'sword','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$this->expectException(InvalidArgumentException::class);app(\App\Domain\Equipment\EquippableItemValidator::class)->equipmentType($helmet);}
public function test_support_and_dual_wield_rules(){ $service=app(CharacterEquipmentService::class);$normal=$this->character(false);$main=$this->handInstance($normal,$this->item('one_hand','sword'));$shield=$this->handInstance($normal,$this->item('off_hand_only','shield'));$dagger=$this->handInstance($normal,$this->item('one_hand','dagger'));$service->equip($normal,$main->uuid,'main_hand');$service->equip($normal,$shield->uuid,'off_hand');$this->assertDatabaseHas('character_equipment',['character_id'=>$normal->id,'slot'=>'off_hand']);$service->unequip($normal,'off_hand');try{$service->equip($normal,$dagger->uuid,'off_hand');$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('segunda arma',$e->getMessage());}$dual=$this->character(true);$dualMain=$this->handInstance($dual,$this->item('one_hand','axe'));$dualOff=$this->handInstance($dual,$this->item('one_hand','dagger'));$service->equip($dual,$dualMain->uuid,'main_hand');$service->equip($dual,$dualOff->uuid,'off_hand');$this->assertSame(2,CharacterEquipment::where('character_id',$dual->id)->count());}
public function test_second_weapon_requires_main_hand(){ $character=$this->character(true);$off=$this->handInstance($character,$this->item('one_hand','dagger'));try{app(CharacterEquipmentService::class)->equip($character,$off->uuid,'off_hand');$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('mano principal',$e->getMessage());}}
public function test_two_hand_confirmation_is_atomic_and_events_are_ordered(){ $character=$this->character();$service=app(CharacterEquipmentService::class);$oldMain=$this->handInstance($character,$this->item('one_hand','sword'));$shield=$this->handInstance($character,$this->item('off_hand_only','shield'));$two=$this->handInstance($character,$this->item('two_hand','axe',7));$service->equip($character,$oldMain->uuid,'main_hand');$service->equip($character,$shield->uuid,'off_hand');try{$service->equip($character,$two->uuid,'main_hand');$this->fail();}catch(EquipmentLoadoutConflictException $e){$this->assertTrue($e->result()->requiresConfirmation());}$this->assertSame('equipped',$shield->fresh()->status);$result=$service->equip($character,$two->uuid,'main_hand',true);$this->assertSame('available',$oldMain->fresh()->status);$this->assertSame('available',$shield->fresh()->status);$this->assertSame('equipped',$two->fresh()->status);$this->assertDatabaseMissing('character_equipment',['character_id'=>$character->id,'slot'=>'off_hand']);$events=ItemInstanceEvent::where('operation_uuid',$result->operationUuid())->orderBy('id')->get();$this->assertSame([ItemInstanceEventType::UNEQUIPPED,ItemInstanceEventType::UNEQUIPPED,ItemInstanceEventType::EQUIPPED],$events->pluck('event_type')->all());$this->assertSame('off_hand',$events[0]->metadata['slot']);$this->assertSame($events[0]->operation_uuid,$events[2]->operation_uuid);$this->assertSame(17,app(CharacterStatsCalculator::class)->calculate($character)->attack());}
public function test_two_hand_blocks_off_hand_and_overview_has_pet(){ $this->seed(\Database\Seeders\CharacterLevelRequirementSeeder::class);$character=$this->character();$two=$this->handInstance($character,$this->item('two_hand','staff'));app(CharacterEquipmentService::class)->equip($character,$two->uuid,'main_hand');$shield=$this->handInstance($character,$this->item('off_hand_only','focus'));try{app(CharacterEquipmentService::class)->equip($character,$shield->uuid,'off_hand');$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('ambas manos',$e->getMessage());}$this->actingAs($character->user)->get(route('characters.overview',$character))->assertOk()->assertSee('Mano secundaria')->assertSee('Mascota')->assertSee('aria-disabled="true"',false);}
}

